// Process the Gemini response and extract styled image
const response = $input.item.json;
const styleConfig = $node['Style Config'].json;

// Extract the generated image from Gemini response
// Note: Actual implementation depends on nano-banana API structure
const styledImageData = response.candidates?.[0]?.content?.parts?.[0]?.inline_data || null;

if (styledImageData) {
  return {
    json: {
      originalName: $node['Download Image'].json.name,
      style: styleConfig.style,
      styleFolder: styleConfig.outputFolder,
      timestamp: new Date().toISOString(),
      success: true
    },
    binary: {
      data: {
        data: styledImageData.data,
        mimeType: styledImageData.mime_type || 'image/png',
        fileName: `styled_${styleConfig.style}_${$node['Download Image'].json.name}`
      }
    }
  };
} else {
  return {
    json: {
      error: 'Style transfer failed',
      originalName: $node['Download Image'].json.name
    }
  };
}

// Configuration for multiple style folders
const styleConfigs = [
  {
    style: 'watercolor',
    inputFolder: '1abc_watercolor_input_folder_id',
    outputFolder: '1def_watercolor_output_folder_id'
  },
  {
    style: 'oil_painting',
    inputFolder: '2abc_oil_input_folder_id',
    outputFolder: '2def_oil_output_folder_id'
  },
  {
    style: 'pencil_sketch',
    inputFolder: '3abc_pencil_input_folder_id',
    outputFolder: '3def_pencil_output_folder_id'
  },
  {
    style: 'pop_art',
    inputFolder: '4abc_pop_input_folder_id',
    outputFolder: '4def_pop_output_folder_id'
  }
];

return styleConfigs.map(config => ({
  json: config
}));

// Group and summarize results by style
const items = $input.all();
const groupedResults = {};

items.forEach(item => {
  const style = item.json.style;
  if (!groupedResults[style]) {
    groupedResults[style] = {
      style: style,
      totalProcessed: 0,
      successful: 0,
      failed: 0,
      images: []
    };
  }

  groupedResults[style].totalProcessed++;
  if (item.json.success) {
    groupedResults[style].successful++;
  } else {
    groupedResults[style].failed++;
  }

  groupedResults[style].images.push({
    name: item.json.originalName,
    status: item.json.success ? 'success' : 'failed',
    timestamp: item.json.timestamp
  });
});

return Object.values(groupedResults).map(group => ({
  json: group
}));
